"j_abstract" -> {
    // Fires in joker_main context (cardarea=="jokers", else branch — not before/not after).
    // mult_mod = (number of jokers on board) * 3
    // Requires joker count from board state — passed in via j.x or a dedicated field.
    // Convention: encode joker count as j.x (set by orchestrator before scoring).
    val jokerCount = j.x.toInt()
    return Fx().apply { multMod = jokerCount * 3.0 }
}

"j_acrobat" -> {
    // Fires in joker_main context (cardarea=="jokers", else branch).
    // Effect: if this is the last hand of the round (handsLeft == 0), Xmult_mod = 3.0
    // handsLeft must be supplied via Sctx (needs a new field) or j.x.
    // Convention: encode handsLeft as j.x (0 = last hand).
    if (j.x == 0.0) {
        return Fx().apply { xMultMod = 3.0 }
    }
}

"j_ancient" -> {
    // Fires in individual context (cardarea=="play") per scored card.
    // Effect: if oc.suit == ancientSuit, xMult = 1.5
    // ancientSuit is a per-round random suit stored in round state.
    // Convention: encode the target suit ordinal in j.x (0=S,1=H,2=D,3=C — matches Suit enum order).
    val ancientSuit = Suit.values().getOrNull(j.x.toInt())
    if (ancientSuit != null && oc.isSuit(ancientSuit)) {
        return Fx().apply { xMult = 1.5 }
    }
}

