"j_baron" -> {
    // Fires in held context (cardarea=="hand") per card held in hand.
    // Effect: if held card is a King (id==13), xMult = 1.5
    // In Lua: returns { x_mult = 1.5 } for held card context (not debuffed).
    // Mapped to Fx.xMult for the held pass (Score.kt applies mult *= fx.xMult in held loop).
    if (oc != null && oc.id == 13 && !oc.debuff) {
        return Fx().apply { xMult = 1.5 }
