}

"j_baseball" -> {
    // Fires in other_joker context: for each other Uncommon joker scoring.
    // In Lua: context.other_joker.config.center.rarity == 2 and self != context.other_joker
    //   -> Xmult_mod = 1.5
    // otherJoker rarity must be available on FJoker or passed via Sctx.
    // Convention: Sctx.otherJoker carries the joker being evaluated; its rarity via FJoker field.
    val oj = ctx.otherJoker
    if (oj != null && oj !== j) {
        // FJoker needs a rarity field; orchestrator sets it. Placeholder: oj.x == 2.0 for rarity 2.
        if (oj.x == 2.0) {
            return Fx().apply { xMultMod = 1.5 }
        }
    }
}

"j_blackboard" -> {
    // Fires in joker_main context (cardarea=="jokers", else branch).
    // Effect: if every card in held hand is black (Spades or Clubs, smeared), Xmult_mod = 3.0
    // In Lua: iterates G.hand.cards; checks is_suit('Clubs', nil, true) || is_suit('Spades', nil, true)
    //   (third arg true = smeared). All held cards must be black.
    // Requires ctx to carry the held hand (Sctx.fullHand is play hand; needs held hand field).
    // Convention: use ctx.scoringHand as held-hand proxy when cardarea=="jokers" in held pass,
    //   OR add a Sctx.heldHand field. Marking as needs=held_card.
    val heldHand = ctx.fullHand // placeholder — orchestrator must wire the actual held hand
    if (heldHand.isNotEmpty() && heldHand.all { c -> c.isSuit(Suit.C, smeared = true) || c.isSuit(Suit.S, smeared = true) }) {
        return Fx().apply { xMultMod = 3.0 }
    }
}

"j_blue_joker" -> {
    // chip_mod = extra * #G.deck.cards; extra = 2
    // deck size must be tracked externally (deckRemaining: Int in Sctx or Score call-site)
    // stub: 0 chips when deck size unknown; cascade must supply deckRemaining
    val deckSize = ctx.deckRemaining  // requires scaling_state / cascade extension
    if (deckSize > 0) return Fx().apply { chipMod = 2.0 * deckSize }
}

"j_blueprint" -> {
    // Finds the joker immediately to the right of itself in G.jokers.cards,
    // then calls that joker's calculate_joker with the same context.
    // Guards: context.blueprint counter prevents infinite loops (> #jokers+1 → abort).
    // Requires: otherJoker = the right-neighbour FJoker, supplied by the cascade before calling calcJoker.
    val neighbour = ctx.otherJoker ?: return null
    if (neighbour.key == j.key) return null  // don't copy yourself
    return calcJoker(neighbour, ctx)  // faithful mirror: same context, neighbour's branch
}

"j_bootstraps" -> {
    // mult_mod = extra.mult * floor((dollars + dollar_buffer) / extra.dollars)
    // extra.mult = 2, extra.dollars = 5
    // dollars must be supplied by cascade (e.g. ctx.dollars: Int)
    val dollars = ctx.dollars  // requires money cascade extension
    val stacks = floor(dollars / 5.0).toInt()
    if (stacks >= 1) return Fx().apply { multMod = 2.0 * stacks }
}

"j_brainstorm" -> {
    // Copies G.jokers.cards[1] — the leftmost joker — with the same context.
    // Guards: context.blueprint counter prevents infinite loops (> #jokers+1 → abort).
    // Requires: otherJoker = the leftmost FJoker on the board, set by cascade before calling calcJoker.
    val leftmost = ctx.otherJoker ?: return null
    if (leftmost.key == j.key) return null  // leftmost is self → no copy
    return calcJoker(leftmost, ctx)  // faithful mirror: same context, leftmost's branch
}

"j_bull" -> {
    // chip_mod = extra * max(0, dollars + dollar_buffer); extra = 2
    val dollars = ctx.dollars  // requires money cascade extension
