"j_business" -> {
    // individual, cardarea == play
    // Guard: other_card:is_face() — id in 11..13
    // Probability: pseudorandom('business') < probabilities.normal / extra  →  1/2 chance
    // Returns dollars = 2 (not a scoring Fx — money side-effect)
    // extra = 2 (probability denominator); dollars earned = 2 (hardcoded in Lua)
    if (oc != null && oc.isFace) {
        // probability: 1 / extra = 1/2; cascade must handle money side-effects
        val hit = Math.random() < (1.0 / 2.0)  // probabilities.normal=1, extra=2
        if (hit) return Fx().apply { /* dollars = 2 side-effect; no chip/mult */ }
    }
    return null
}

"j_caino" -> {
    // joker_main: apply accumulated caino_xmult when > 1
