"j_faceless" -> {
    // Trigger once per discard event (when oc is the last card in full_hand)
    // Count face cards (id in 11..13) in full_hand; if >= 3, award $5
    // No chip/mult effect — purely a money effect; needs money + discard-context support
    if (oc != null && oc == ctx.fullHand.lastOrNull()) {
        val faceCount = ctx.fullHand.count { it.isFace }
        if (faceCount >= 3) return Fx() // signal: earn $5 (money cascade not in Score.kt)
    }
    return null
}

