"j_flower_pot" -> {
    val suits = mutableMapOf(Suit.H to 0, Suit.D to 0, Suit.S to 0, Suit.C to 0)
    // first pass: non-wild cards with smeared matching
    for (card in ctx.scoringHand) {
        if (card.enhancement != Enhancement.WILD) {
            if (card.isSuit(Suit.H, smeared = true) && suits[Suit.H] == 0) suits[Suit.H] = 1
            else if (card.isSuit(Suit.D, smeared = true) && suits[Suit.D] == 0) suits[Suit.D] = 1
            else if (card.isSuit(Suit.S, smeared = true) && suits[Suit.S] == 0) suits[Suit.S] = 1
            else if (card.isSuit(Suit.C, smeared = true) && suits[Suit.C] == 0) suits[Suit.C] = 1
        }
    }
    // second pass: wild cards fill remaining gaps
    for (card in ctx.scoringHand) {
        if (card.enhancement == Enhancement.WILD) {
            if (card.isSuit(Suit.H) && suits[Suit.H] == 0) suits[Suit.H] = 1
            else if (card.isSuit(Suit.D) && suits[Suit.D] == 0) suits[Suit.D] = 1
            else if (card.isSuit(Suit.S) && suits[Suit.S] == 0) suits[Suit.S] = 1
            else if (card.isSuit(Suit.C) && suits[Suit.C] == 0) suits[Suit.C] = 1
        }
    }
    if (suits.values.all { it > 0 }) return Fx().apply { xMultMod = 3.0 }
}

