    if (oc.enhancement == Enhancement.LUCKY && oc.luckyTrigger) {
        j.x += 0.25   // ability.x_mult += ability.extra
        return Fx()   // no immediate scoring return; the x_mult is reported at jokerMain pass
    }
}
