    "j_midas_mask" -> {
        val faces = ctx.scoringHand.filter { it.isFace }
        if (faces.isNotEmpty()) {
            for (card in faces) card.enhancement = Enhancement.GOLD
            return Fx()   // signal something happened; no chip/mult modifier
        }
