// BEFORE (ctx.before)
"j_obelisk" -> {
    // Count plays per hand type; if scoringName is the most-played (no other hand >= its count),
    // increment j.x by 0.2; else reset j.x to 1.
    val currentPlayed = ctx.handPlays[ctx.scoringName] ?: 0
    val isTopHand = ctx.handPlays.entries
        .filter { it.key != ctx.scoringName && it.value.visible }
        .none { it.value.played >= currentPlayed }
    if (isTopHand) {
        j.x += 0.2
    } else {
        j.x = 1.0
    }
